mapper.select:
SELECT t.id AS id, t.transaction_id AS transactionId, c.id AS companyId, c.name AS companyName,
t.place AS place, t.transaction_date AS transactionDate, t.transaction_name AS transactionName,
t.transaction_type_id AS transactionTypeId, tt.name AS transactionTypeName,
t.outsend_province AS outsendProvince,
t.gen_type_id AS genTypeId, gt.name AS genTypeName,
t.transaction_period_id AS transactionPeriodId, tp.name AS transactionPeriodName,
t.transaction_start_year AS transactionStartYear, t.transaction_end_year AS transactionEndYear,
t.contract_start_date AS contractStartDate, t.contract_end_date AS contractEndDate,
t.is_green AS isGreen, t.is_cheap AS isCheap,
t.base_price AS basePrice, t.market_size AS marketSize, t.market_participation_capacity AS marketParticipationCapacity, t.market_avg_price AS marketAvgPrice, t.chng_participation_capacity AS chngParticipationCapacity, t.chng_transaction_amount AS chngTransactionAmount, t.chng_avg_price AS chngTradedPrice, t.env_premium AS envPremium,
t.data_source AS dataSource, t.note AS note, t.created_at AS createdAt
FROM longterm_transactions t JOIN companies c ON c.id = t.company_id LEFT JOIN transaction_types tt ON tt.id = t.transaction_type_id LEFT JOIN gen_types gt ON gt.id = t.gen_type_id LEFT JOIN transaction_periods tp ON tp.id = t.transaction_period_id
WHERE 1=1
AND t.company_id = #{companyId}
AND t.gen_type_id IN #{item}
AND t.transaction_type_id IN #{item}
AND t.transaction_period_id IN #{item}
AND t.contract_start_date >= #{contractStartDate}
AND t.contract_end_date <= #{contractEndDate}
AND t.is_green IN #{item}

SELECT
    c.id AS companyId,
    c.name AS companyName,
    t.chng_transaction_amount AS chngTransactionAmount,
    t.chng_avg_price AS chngTradedPrice,
    t.base_price AS basePrice

FROM companies c
LEFT JOIN longterm_transactions t
    ON c.id = t.company_id

        AND t.gen_type_id IN
        #{item}


        AND t.transaction_type_id IN
        #{item}


        AND t.transaction_period_id IN
        #{item}


        AND t.contract_start_date >= #{contractStartDate}


        AND t.contract_end_date <= #{contractEndDate}


        AND t.is_green IN
        #{item}

ORDER BY c.id

SELECT
    DATE_FORMAT(t.contract_start_date,'%Y-%m') AS period,
    COALESCE(SUM(t.chng_transaction_amount),0) AS tradedPower,
    COALESCE(SUM(t.base_price * t.chng_transaction_amount) / NULLIF(SUM(t.chng_transaction_amount),0),0) AS weightedBenchmarkPrice,
    COALESCE(SUM(t.chng_avg_price * t.chng_transaction_amount) / NULLIF(SUM(t.chng_transaction_amount),0),0) AS chngTradedPrice
FROM longterm_transactions t
WHERE 1=1

    AND t.gen_type_id IN
    #{item}


    AND t.transaction_type_id IN
    #{item}


    AND t.transaction_period_id IN
    #{item}


    AND t.contract_start_date >= #{contractStartDate}


    AND t.contract_end_date <= #{contractEndDate}


    AND t.is_green IN
    #{item}

GROUP BY DATE_FORMAT(t.contract_start_date,'%Y-%m')
ORDER BY DATE_FORMAT(t.contract_start_date,'%Y-%m')
